function solve(n, edges, label) {
    // Build adjacency list
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let maxLen = 0;
    const visited = new Set();

    function isPalindrome(s) {
        let left = 0;
        let right = s.length - 1;
        while (left < right) {
            if (s[left] !== s[right]) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }

    function backtrack(node, path) {
        const currentStr = path.map(i => label[i]).join('');
        if (isPalindrome(currentStr)) {
            maxLen = Math.max(maxLen, currentStr.length);
        }

        for (const neighbor of adj[node]) {
            if (!visited.has(neighbor)) {
                visited.add(neighbor);
                path.push(neighbor);
                backtrack(neighbor, path);
                path.pop();
                visited.delete(neighbor);
            }
        }
    }

    for (let i = 0; i < n; i++) {
        visited.add(i);
        backtrack(i, [i]);
        visited.delete(i);
    }

    return maxLen;
}

